const files = $input.all();
const items = [];

files.forEach(f => {
  const file = f.json;
  if (!file.content) return;

  const content = Buffer.from(file.content, 'base64').toString('utf8');
  const fmMatch = content.match(/^---\n([\s\S]+?)\n---/);
  if (!fmMatch) return;

  const fm = {};
  fmMatch[1].split('\n').forEach(line => {
    const colonIdx = line.indexOf(':');
    if (colonIdx === -1) return;
    const key = line.slice(0, colonIdx).trim();
    const val = line.slice(colonIdx + 1).trim().replace(/^"(.*)"$/, '$1');
    fm[key] = val;
  });

  items.push({
    id: fm.id,
    type: fm.type,
    project: fm.project,
    title: fm.title,
    status: fm.status,
    priority: fm.priority,
    created: fm.created,
    processing_started: fm.processing_started || null,
    processing_updated: fm.processing_updated || null,
    current_agent: fm.current_agent || null,
    retry_count: parseInt(fm.retry_count) || 0,
    last_error: fm.last_error || null,
    api_cost_usd: parseFloat(fm.api_cost_usd) || 0,
    deployed_at: fm.deployed_at || null,
    file_path: file.path || file.url?.split('/contents/')[1]
  });
});

return [{ json: { items, generated_at: new Date().toISOString() } }];

const itemsObj = $('Parse Frontmatters').all();
const items = itemsObj[0].json.items;
const now = new Date();
const dateStr = now.toISOString().split('T')[0];

const STALE_MS = 30 * 60 * 1000;
const TERMINAL = ['documented', 'needs-human', 'deploy-failed'];

const stats = {
  date: dateStr,
  total_items: items.length,
  by_status: {},
  by_project: {},
  by_type: {},
  completed_today: 0,
  costs: {
    total: 0,
    today: 0,
    by_agent: {},
    by_project: {}
  },
  performance: {
    avg_cycle_time_hours: 0,
    avg_retry_count: 0,
    agent_fail_rate: {},
    items_needs_human: 0,
    items_deploy_failed: 0
  },
  throughput: {
    completed_this_week: 0,
    completed_this_month: 0
  }
};

let cycleTimes = [];
let retryCounts = [];
let agentFails = {};
let agentCalls = {};

const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const monthAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

items.forEach(item => {
  stats.by_status[item.status] = (stats.by_status[item.status] || 0) + 1;
  stats.by_type[item.type] = (stats.by_type[item.type] || 0) + 1;

  if (!stats.by_project[item.project]) {
    stats.by_project[item.project] = { total: 0, active: 0, completed: 0 };
    stats.costs.by_project[item.project] = 0;
  }
  stats.by_project[item.project].total++;

  stats.costs.total += item.api_cost_usd || 0;
  stats.costs.by_project[item.project] += item.api_cost_usd || 0;

  if (item.current_agent) {
    stats.costs.by_agent[item.current_agent] = (stats.costs.by_agent[item.current_agent] || 0) + (item.api_cost_usd || 0);
    agentCalls[item.current_agent] = (agentCalls[item.current_agent] || 0) + 1;
  }

  if (item.status === 'documented') {
    stats.by_project[item.project].completed++;
    if (item.processing_updated?.startsWith(dateStr)) {
      stats.completed_today++;
      stats.costs.today += item.api_cost_usd || 0;
    }
    const upd = new Date(item.processing_updated);
    if (upd >= weekAgo) stats.throughput.completed_this_week++;
    if (upd >= monthAgo) stats.throughput.completed_this_month++;

    if (item.processing_started && item.processing_updated) {
      const cycleMs = new Date(item.processing_updated) - new Date(item.processing_started);
      cycleTimes.push(cycleMs / 3600000);
    }
  } else if (!['new'].includes(item.status)) {
    stats.by_project[item.project].active++;
  }

  if (item.status === 'needs-human') {
    stats.performance.items_needs_human++;
    if (item.current_agent) {
      agentFails[item.current_agent] = (agentFails[item.current_agent] || 0) + 1;
    }
  }
  if (item.status === 'deploy-failed') stats.performance.items_deploy_failed++;

  if (item.retry_count > 0) retryCounts.push(item.retry_count);
});

if (cycleTimes.length > 0) {
  stats.performance.avg_cycle_time_hours = Math.round(cycleTimes.reduce((a, b) => a + b, 0) / cycleTimes.length * 10) / 10;
}
if (retryCounts.length > 0) {
  stats.performance.avg_retry_count = Math.round(retryCounts.reduce((a, b) => a + b, 0) / retryCounts.length * 10) / 10;
}

Object.keys(agentFails).forEach(agent => {
  stats.performance.agent_fail_rate[agent] = agentCalls[agent] ? Math.round((agentFails[agent] / agentCalls[agent]) * 100) / 100 : 0;
});

stats.costs.total = Math.round(stats.costs.total * 10000) / 10000;
stats.costs.today = Math.round(stats.costs.today * 10000) / 10000;
Object.keys(stats.costs.by_project).forEach(p => stats.costs.by_project[p] = Math.round(stats.costs.by_project[p] * 10000) / 10000);
Object.keys(stats.costs.by_agent).forEach(a => stats.costs.by_agent[a] = Math.round(stats.costs.by_agent[a] * 10000) / 10000);

const contentBase64 = Buffer.from(JSON.stringify(stats, null, 2)).toString('base64');

return [{ json: { date: dateStr, contentBase64 } }];
